package istiocsr

import (
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"reflect"
	"strings"

	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/types"
	"k8s.io/apimachinery/pkg/util/validation/field"
	"sigs.k8s.io/controller-runtime/pkg/client"

	certmanagerv1 "github.com/cert-manager/cert-manager/pkg/apis/certmanager/v1"

	"github.com/openshift/cert-manager-operator/api/operator/v1alpha1"
	"github.com/openshift/cert-manager-operator/pkg/controller/common"
	"github.com/openshift/cert-manager-operator/pkg/operator/assets"
)

const (
	caVolumeMountPath = "/var/run/configmaps/istio-csr"
)

var errInvalidIssuerRefConfig = fmt.Errorf("invalid issuerRef config")

func (r *Reconciler) createOrApplyDeployments(istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string, istioCSRCreateRecon bool) error {
	desired, err := r.getDeploymentObject(istiocsr, resourceLabels)
	if err != nil {
		return fmt.Errorf("failed to generate deployment resource for creation in %s: %w", istiocsr.GetNamespace(), err)
	}

	deploymentName := fmt.Sprintf("%s/%s", desired.GetNamespace(), desired.GetName())
	r.log.V(4).Info("reconciling deployment resource", "name", deploymentName)
	fetched := &appsv1.Deployment{}
	exist, err := r.Exists(r.ctx, client.ObjectKeyFromObject(desired), fetched)
	if err != nil {
		return common.FromClientError(err, "failed to check %s deployment resource already exists", deploymentName)
	}

	if exist {
		if istioCSRCreateRecon {
			r.eventRecorder.Eventf(istiocsr, corev1.EventTypeWarning, "ResourceAlreadyExists", "%s deployment resource already exists, maybe from previous installation", deploymentName)
		}
		if hasObjectChanged(desired, fetched) {
			r.log.V(1).Info("deployment has been modified, updating to desired state", "name", deploymentName)
			if err := r.UpdateWithRetry(r.ctx, desired); err != nil {
				return common.FromClientError(err, "failed to update %s deployment resource", deploymentName)
			}
			r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "deployment resource %s reconciled back to desired state", deploymentName)
		} else {
			r.log.V(4).Info("deployment resource already exists and is in expected state", "name", deploymentName)
		}
	}

	if !exist {
		if err := r.Create(r.ctx, desired); err != nil {
			return common.FromClientError(err, "failed to create %s deployment resource", deploymentName)
		}
		r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "deployment resource %s created", deploymentName)
	}

	if err := r.updateImageInStatus(istiocsr, desired); err != nil {
		return common.FromClientError(err, "failed to update %s/%s istiocsr status with image info", istiocsr.GetNamespace(), istiocsr.GetName())
	}
	return nil
}

func (r *Reconciler) getDeploymentObject(istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) (*appsv1.Deployment, error) {
	if err := r.assertIssuerRefExists(istiocsr); err != nil {
		return nil, fmt.Errorf("failed to verify issuer in %s/%s: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
	}

	deployment := decodeDeploymentObjBytes(assets.MustAsset(deploymentAssetName))

	common.UpdateNamespace(deployment, istiocsr.GetNamespace())
	common.UpdateResourceLabels(deployment, resourceLabels)
	updatePodTemplateLabels(deployment, resourceLabels)

	updateArgList(deployment, istiocsr)

	if err := updateResourceRequirement(deployment, istiocsr); err != nil {
		return nil, fmt.Errorf("failed to update resource requirements: %w", err)
	}
	if err := updateAffinityRules(deployment, istiocsr); err != nil {
		return nil, fmt.Errorf("failed to update affinity rules: %w", err)
	}
	if err := updatePodTolerations(deployment, istiocsr); err != nil {
		return nil, fmt.Errorf("failed to update pod tolerations: %w", err)
	}
	if err := updateNodeSelector(deployment, istiocsr); err != nil {
		return nil, fmt.Errorf("failed to update node selector: %w", err)
	}
	if err := r.updateImage(deployment); err != nil {
		return nil, common.NewIrrecoverableError(err, "failed to update image %s/%s", istiocsr.GetNamespace(), istiocsr.GetName())
	}
	if err := r.updateVolumes(deployment, istiocsr, resourceLabels); err != nil {
		return nil, fmt.Errorf("failed to update volume %s/%s: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
	}

	return deployment, nil
}

func (r *Reconciler) updateImage(deployment *appsv1.Deployment) error {
	image := os.Getenv(istiocsrImageNameEnvVarName)
	if image == "" {
		return fmt.Errorf("%s environment variable with istiocsr image not set", istiocsrImageNameEnvVarName)
	}
	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == istiocsrContainerName {
			deployment.Spec.Template.Spec.Containers[i].Image = image
		}
	}
	return nil
}

func (r *Reconciler) updateImageInStatus(istiocsr *v1alpha1.IstioCSR, deployment *appsv1.Deployment) error {
	for _, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == istiocsrContainerName {
			if istiocsr.Status.IstioCSRImage == container.Image {
				return nil
			}
			istiocsr.Status.IstioCSRImage = container.Image
		}
	}
	return r.updateStatus(r.ctx, istiocsr)
}

func updatePodTemplateLabels(deployment *appsv1.Deployment, resourceLabels map[string]string) {
	deployment.Spec.Template.Labels = resourceLabels
}

func updateArgList(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) {
	istiocsrConfigs := istiocsr.Spec.IstioCSRConfig
	// Default clusterID to "Kubernetes" if not provided.
	clusterID := defaultClusterID
	if istiocsrConfigs.Server != nil && istiocsrConfigs.Server.ClusterID != "" {
		clusterID = istiocsrConfigs.Server.ClusterID
	}
	args := []string{
		fmt.Sprintf("--log-level=%d", istiocsrConfigs.LogLevel),
		fmt.Sprintf("--log-format=%s", istiocsrConfigs.LogFormat),
		"--metrics-port=9402", "--readiness-probe-port=6060", "--readiness-probe-path=/readyz",
		fmt.Sprintf("--certificate-namespace=%s", istiocsrConfigs.Istio.Namespace),
		"--issuer-enabled=true", "--preserve-certificate-requests=false",
		fmt.Sprintf("--issuer-name=%s", istiocsrConfigs.CertManager.IssuerRef.Name),
		fmt.Sprintf("--issuer-kind=%s", istiocsrConfigs.CertManager.IssuerRef.Kind),
		fmt.Sprintf("--issuer-group=%s", istiocsrConfigs.CertManager.IssuerRef.Group),
		fmt.Sprintf("--root-ca-file=%s/%s", caVolumeMountPath, IstiocsrCAKeyName),
		fmt.Sprintf("--serving-certificate-dns-names=cert-manager-istio-csr.%s.svc", istiocsr.GetNamespace()),
		fmt.Sprintf("--serving-certificate-duration=%.0fm", istiocsrConfigs.IstiodTLSConfig.CertificateDuration.Minutes()),
		fmt.Sprintf("--trust-domain=%s", istiocsrConfigs.IstiodTLSConfig.TrustDomain),
		fmt.Sprintf("--cluster-id=%s", clusterID),
		fmt.Sprintf("--max-client-certificate-duration=%.0fm", istiocsrConfigs.IstiodTLSConfig.MaxCertificateDuration.Minutes()),
		"--serving-address=0.0.0.0:6443",
		fmt.Sprintf("--serving-certificate-key-size=%d", istiocsrConfigs.IstiodTLSConfig.PrivateKeySize),
		fmt.Sprintf("--serving-signature-algorithm=%s", istiocsrConfigs.IstiodTLSConfig.PrivateKeyAlgorithm),
		"--enable-client-cert-authenticator=false",
		fmt.Sprintf("--leader-election-namespace=%s", istiocsrConfigs.Istio.Namespace),
		"--disable-kubernetes-client-rate-limiter=false", "--istiod-cert-enabled=false",
		fmt.Sprintf("--istiod-cert-namespace=%s", istiocsrConfigs.Istio.Namespace),
		fmt.Sprintf("--istiod-cert-duration=%.0fm", istiocsrConfigs.IstiodTLSConfig.CertificateDuration.Minutes()),
		fmt.Sprintf("--istiod-cert-renew-before=%.0fm", istiocsrConfigs.IstiodTLSConfig.CertificateRenewBefore.Minutes()),
		fmt.Sprintf("--istiod-cert-key-algorithm=%s", istiocsrConfigs.IstiodTLSConfig.PrivateKeyAlgorithm),
		fmt.Sprintf("--istiod-cert-key-size=%d", istiocsrConfigs.IstiodTLSConfig.PrivateKeySize),
		fmt.Sprintf("--istiod-cert-additional-dns-names=%s", strings.Join(istiocsr.Spec.IstioCSRConfig.IstiodTLSConfig.CertificateDNSNames, ",")),
		fmt.Sprintf("--istiod-cert-istio-revisions=%s", strings.Join(istiocsrConfigs.Istio.Revisions, ",")),
	}

	// Add configmap-namespace-selector argument if configured
	if istiocsrConfigs.IstioDataPlaneNamespaceSelector != "" {
		args = append(args, fmt.Sprintf("--configmap-namespace-selector=%s", istiocsrConfigs.IstioDataPlaneNamespaceSelector))
	}

	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == istiocsrContainerName {
			deployment.Spec.Template.Spec.Containers[i].Args = args
		}
	}
}

func updateResourceRequirement(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) error {
	if reflect.ValueOf(istiocsr.Spec.IstioCSRConfig.Resources).IsZero() {
		return nil
	}
	if err := common.ValidateResourceRequirements(istiocsr.Spec.IstioCSRConfig.Resources,
		field.NewPath("spec", "istioCSRConfig")); err != nil {
		return err
	}
	for i := range deployment.Spec.Template.Spec.Containers {
		deployment.Spec.Template.Spec.Containers[i].Resources = istiocsr.Spec.IstioCSRConfig.Resources
	}
	return nil
}

func updateAffinityRules(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) error {
	if istiocsr.Spec.IstioCSRConfig.Affinity == nil {
		return nil
	}
	if err := common.ValidateAffinityRules(istiocsr.Spec.IstioCSRConfig.Affinity,
		field.NewPath("spec", "istioCSRConfig")); err != nil {
		return err
	}
	deployment.Spec.Template.Spec.Affinity = istiocsr.Spec.IstioCSRConfig.Affinity
	return nil
}

func updatePodTolerations(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) error {
	if istiocsr.Spec.IstioCSRConfig.Tolerations == nil {
		return nil
	}
	if err := common.ValidateTolerationsConfig(istiocsr.Spec.IstioCSRConfig.Tolerations,
		field.NewPath("spec", "istioCSRConfig")); err != nil {
		return err
	}
	deployment.Spec.Template.Spec.Tolerations = istiocsr.Spec.IstioCSRConfig.Tolerations
	return nil
}

func updateNodeSelector(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) error {
	if istiocsr.Spec.IstioCSRConfig.NodeSelector == nil {
		return nil
	}
	if err := common.ValidateNodeSelectorConfig(istiocsr.Spec.IstioCSRConfig.NodeSelector,
		field.NewPath("spec", "istioCSRConfig")); err != nil {
		return err
	}
	deployment.Spec.Template.Spec.NodeSelector = istiocsr.Spec.IstioCSRConfig.NodeSelector
	return nil
}

func (r *Reconciler) assertIssuerRefExists(istiocsr *v1alpha1.IstioCSR) error {
	issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
	if issuerRefKind != clusterIssuerKind && issuerRefKind != issuerKind {
		return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "spec.istioCSRConfig.certManager.issuerRef.kind can be any of `%s` or `%s`, configured: %s", clusterIssuerKind, issuerKind, issuerRefKind)
	}

	issuerRefGroup := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Group)
	if issuerRefGroup != issuerGroup {
		return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "spec.istioCSRConfig.certManager.issuerRef.group can be only `%s`, configured: %s", issuerGroup, issuerRefGroup)
	}

	obj, err := r.getIssuer(istiocsr)
	if err != nil {
		return common.FromClientError(err, "failed to fetch issuer")
	}

	var issuerConfig certmanagerv1.IssuerConfig
	switch issuerRefKind {
	case clusterIssuerKind:
		clusterIssuer, ok := obj.(*certmanagerv1.ClusterIssuer)
		if !ok {
			return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "failed to convert to ClusterIssuer")
		}
		issuerConfig = clusterIssuer.Spec.IssuerConfig
	case issuerKind:
		issuer, ok := obj.(*certmanagerv1.Issuer)
		if !ok {
			return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "failed to convert to Issuer")
		}
		issuerConfig = issuer.Spec.IssuerConfig
	}
	if issuerConfig.ACME != nil {
		return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "spec.istioCSRConfig.certManager.issuerRef uses unsupported ACME issuer")
	}

	if err := r.updateWatchLabel(obj, istiocsr); err != nil {
		return common.FromClientError(err, "failed to update watch label on cert-manager issuer %s", istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Name)
	}

	return nil
}

func (r *Reconciler) updateVolumes(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
	// Use user-configured CA certificate if provided
	if istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate != nil {
		if err := r.handleUserProvidedCA(deployment, istiocsr, resourceLabels); err != nil {
			return common.FromError(err, "failed to validate and mount CA certificate ConfigMap")
		}
		return nil
	}

	// Fall back to issuer-based CA certificate if CA certificate is not configured
	// Handle issuer-based CA configuration
	if err := r.handleIssuerBasedCA(deployment, istiocsr, resourceLabels); err != nil {
		return err
	}

	return nil
}

// handleUserProvidedCA processes user-provided CA certificate configuration.
//
// It performs the following operations:
//  1. Validates that the source ConfigMap exists
//  2. Adds a watch label to the source ConfigMap for change tracking
//  3. Validates that the ConfigMap contains the specified key and is a valid CA certificate
//  4. Creates or updates a copy of the ConfigMap in the IstioCSR namespace
//  5. Configures the deployment to mount the CA certificate volume
//
// The caller must ensure that `istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate`
// is not nil before calling this function to avoid a panic.
//
// Returns an error if any validation fails or if ConfigMap operations fail.
func (r *Reconciler) handleUserProvidedCA(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
	caCertConfig := istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate

	// Determine the namespace - use specified namespace or default to IstioCSR namespace
	namespace := caCertConfig.Namespace
	if namespace == "" {
		namespace = istiocsr.GetNamespace()
	}

	// Validate that the source ConfigMap exists
	sourceConfigMapKey := types.NamespacedName{
		Name:      caCertConfig.Name,
		Namespace: namespace,
	}

	sourceConfigMap := &corev1.ConfigMap{}
	if err := r.Get(r.ctx, sourceConfigMapKey, sourceConfigMap); err != nil {
		return common.NewIrrecoverableError(err, "failed to fetch CA certificate ConfigMap %s/%s", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name)
	}

	// Add watch label to the source ConfigMap to trigger reconciliation on changes.
	// This is done before validation so that if validation fails now, fixing the ConfigMap
	// will trigger reconciliation.
	if err := r.updateWatchLabel(sourceConfigMap, istiocsr); err != nil {
		return common.FromClientError(err, "failed to update watch label on CA certificate ConfigMap %s/%s", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name)
	}

	// Validate that the specified key exists in the ConfigMap
	if _, exists := sourceConfigMap.Data[caCertConfig.Key]; !exists {
		return common.NewIrrecoverableError(fmt.Errorf("key %q not found in ConfigMap %s/%s", caCertConfig.Key, sourceConfigMapKey.Namespace, sourceConfigMapKey.Name), "invalid CA certificate ConfigMap %s/%s", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name)
	}

	// Validate that the key contains PEM-formatted content
	pemData := sourceConfigMap.Data[caCertConfig.Key]
	if err := r.validatePEMData(pemData); err != nil {
		return common.NewIrrecoverableError(err, "invalid PEM data in CA certificate ConfigMap %s/%s key %q", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name, caCertConfig.Key)
	}

	// Create a managed copy of the ConfigMap in the IstioCSR namespace.
	// The operator does not directly mount the user-provided ConfigMap but creates a managed copy
	// (cert-manager-istio-csr-issuer-ca-copy) in the IstioCSR namespace. This approach enables the
	// operator to validate any changes to the source ConfigMap before propagating them to the istio-csr
	// agent, as ConfigMap changes automatically propagate to mounted pods. The watch label on the source
	// ConfigMap triggers reconciliation when modified, allowing the operator to re-validate and update
	// its managed copy. Additionally, if a user directly modifies the operator-managed copy, it will be
	// reconciled back to the desired state derived from the validated source ConfigMap.
	if err := r.createOrUpdateCAConfigMap(istiocsr, pemData, resourceLabels); err != nil {
		return common.FromClientError(err, "failed to create CA certificate ConfigMap copy")
	}

	// Mount the copied CA certificate ConfigMap (always uses the standard name)
	updateVolumeWithIssuerCA(deployment)

	return nil
}

// handleIssuerBasedCA handles the creation of CA ConfigMap from issuer secret and volume mounting.
func (r *Reconciler) handleIssuerBasedCA(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
	var (
		issuerConfig certmanagerv1.IssuerConfig
	)

	obj, err := r.getIssuer(istiocsr)
	if err != nil {
		return common.FromClientError(err, "failed to fetch issuer")
	}

	issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
	switch issuerRefKind {
	case clusterIssuerKind:
		clusterIssuer, ok := obj.(*certmanagerv1.ClusterIssuer)
		if !ok {
			return common.FromClientError(fmt.Errorf("failed to convert to ClusterIssuer"), "failed to fetch issuer")
		}
		issuerConfig = clusterIssuer.Spec.IssuerConfig
	case issuerKind:
		issuer, ok := obj.(*certmanagerv1.Issuer)
		if !ok {
			return common.FromClientError(fmt.Errorf("failed to convert to Issuer"), "failed to fetch issuer")
		}
		issuerConfig = issuer.Spec.IssuerConfig
	}

	shouldUpdateVolume := false

	if issuerConfig.CA != nil && issuerConfig.CA.SecretName != "" {
		if err := r.createCAConfigMapFromIssuerSecret(istiocsr, issuerConfig, resourceLabels); err != nil {
			return common.FromClientError(err, "failed to create CA ConfigMap")
		}
		shouldUpdateVolume = true
	}

	if issuerConfig.CA == nil {
		if err := r.createCAConfigMapFromIstiodCertificate(istiocsr, resourceLabels); err != nil {
			return common.FromClientError(err, "failed to create CA ConfigMap")
		}
		shouldUpdateVolume = true
	}

	if shouldUpdateVolume {
		updateVolumeWithIssuerCA(deployment)
	}

	return nil
}

func updateVolumeWithIssuerCA(deployment *appsv1.Deployment) {
	const (
		caVolumeName = "root-ca"
	)
	var (
		defaultMode = int32(420)
	)

	desiredVolumeMount := corev1.VolumeMount{
		Name:      caVolumeName,
		MountPath: caVolumeMountPath,
		ReadOnly:  true,
	}

	desiredVolume := corev1.Volume{
		Name: caVolumeName,
		VolumeSource: corev1.VolumeSource{
			ConfigMap: &corev1.ConfigMapVolumeSource{
				LocalObjectReference: corev1.LocalObjectReference{
					Name: IstiocsrCAConfigMapName,
				},
				Items: []corev1.KeyToPath{
					{
						Key:  IstiocsrCAKeyName,
						Path: IstiocsrCAKeyName,
						Mode: &defaultMode,
					},
				},
				DefaultMode: &defaultMode,
			},
		},
	}

	// Update or append volume mount in the istio-csr container
	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == istiocsrContainerName {
			volumeMountExists := false
			for j, vm := range container.VolumeMounts {
				if vm.Name == caVolumeName {
					deployment.Spec.Template.Spec.Containers[i].VolumeMounts[j] = desiredVolumeMount
					volumeMountExists = true
					break
				}
			}
			if !volumeMountExists {
				deployment.Spec.Template.Spec.Containers[i].VolumeMounts = append(
					deployment.Spec.Template.Spec.Containers[i].VolumeMounts,
					desiredVolumeMount,
				)
			}
			break
		}
	}

	// Update or append volume in the deployment
	volumeExists := false
	for i, vol := range deployment.Spec.Template.Spec.Volumes {
		if vol.Name == caVolumeName {
			deployment.Spec.Template.Spec.Volumes[i] = desiredVolume
			volumeExists = true
			break
		}
	}
	if !volumeExists {
		deployment.Spec.Template.Spec.Volumes = append(
			deployment.Spec.Template.Spec.Volumes,
			desiredVolume,
		)
	}
}

func (r *Reconciler) getIssuer(istiocsr *v1alpha1.IstioCSR) (client.Object, error) {
	issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
	key := client.ObjectKey{
		Name:      istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Name,
		Namespace: istiocsr.Spec.IstioCSRConfig.Istio.Namespace,
	}

	var object client.Object
	switch issuerRefKind {
	case clusterIssuerKind:
		object = &certmanagerv1.ClusterIssuer{}
	case issuerKind:
		object = &certmanagerv1.Issuer{}
	}

	if err := r.Get(r.ctx, key, object); err != nil {
		return nil, fmt.Errorf("failed to fetch %q issuer: %w", key, err)
	}
	return object, nil
}

func (r *Reconciler) createCAConfigMapFromIstiodCertificate(istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
	istiodCertificate, err := r.getCertificateObject(istiocsr, resourceLabels)
	if err != nil {
		return common.FromClientError(err, "failed to fetch istiod certificate")
	}

	secretKey := client.ObjectKey{
		Name:      istiodCertificate.Spec.SecretName,
		Namespace: istiodCertificate.GetNamespace(),
	}
	secret := &corev1.Secret{}
	if err := r.Get(r.ctx, secretKey, secret); err != nil {
		return fmt.Errorf("failed to fetch secret in issuer: %w", err)
	}
	if err := r.updateWatchLabel(secret, istiocsr); err != nil {
		return err
	}

	certData := string(secret.Data[IstiocsrCAKeyName])
	return r.createOrUpdateCAConfigMap(istiocsr, certData, resourceLabels)
}

func (r *Reconciler) createCAConfigMapFromIssuerSecret(istiocsr *v1alpha1.IstioCSR, issuerConfig certmanagerv1.IssuerConfig, resourceLabels map[string]string) error {
	if issuerConfig.CA.SecretName == "" {
		return fmt.Errorf("failed to fetch CA certificate configured for the %s issuer of CA type", istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Name)
	}

	secretKey := client.ObjectKey{
		Name:      issuerConfig.CA.SecretName,
		Namespace: istiocsr.Spec.IstioCSRConfig.Istio.Namespace,
	}
	secret := &corev1.Secret{}
	if err := r.Get(r.ctx, secretKey, secret); err != nil {
		return fmt.Errorf("failed to fetch secret in issuer: %w", err)
	}
	if err := r.updateWatchLabel(secret, istiocsr); err != nil {
		return err
	}

	certData := string(secret.Data[IstiocsrCAKeyName])
	return r.createOrUpdateCAConfigMap(istiocsr, certData, resourceLabels)
}

// createOrUpdateCAConfigMap creates or updates the CA ConfigMap with the provided certificate data.
func (r *Reconciler) createOrUpdateCAConfigMap(istiocsr *v1alpha1.IstioCSR, certData string, resourceLabels map[string]string) error {
	if certData == "" {
		return fmt.Errorf("failed to find CA certificate")
	}

	configmapKey := client.ObjectKey{
		Name:      IstiocsrCAConfigMapName,
		Namespace: istiocsr.GetNamespace(),
	}
	fetched := &corev1.ConfigMap{}
	exist, err := r.Exists(r.ctx, configmapKey, fetched)
	if err != nil {
		return fmt.Errorf("failed to check if CA configmap exists: %w", err)
	}

	desired := &corev1.ConfigMap{
		ObjectMeta: metav1.ObjectMeta{
			Name:      configmapKey.Name,
			Namespace: configmapKey.Namespace,
			Labels:    resourceLabels,
		},
		Data: map[string]string{
			IstiocsrCAKeyName: certData,
		},
	}

	if exist && hasObjectChanged(desired, fetched) {
		r.log.V(1).Info("ca configmap need update", "name", configmapKey)
		if err := r.UpdateWithRetry(r.ctx, desired); err != nil {
			return fmt.Errorf("failed to update %s configmap resource: %w", configmapKey, err)
		}
		r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "configmap resource %s reconciled back to desired state", configmapKey)
	} else {
		r.log.V(4).Info("configmap resource already exists and is in expected state", "name", configmapKey)
	}

	if !exist {
		if err := r.Create(r.ctx, desired); err != nil {
			return fmt.Errorf("failed to create %s configmap resource: %w", configmapKey, err)
		}
		r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "configmap resource %s created", configmapKey)
	}

	return nil
}

func (r *Reconciler) validatePEMData(pemData string) error {
	if pemData == "" {
		return fmt.Errorf("PEM data is empty")
	}

	// Parse the first certificate from PEM data
	block, _ := pem.Decode([]byte(pemData))
	if block == nil {
		return fmt.Errorf("no valid PEM data found")
	}

	if block.Type != "CERTIFICATE" {
		return fmt.Errorf("PEM block is not a certificate, found: %s", block.Type)
	}

	cert, err := x509.ParseCertificate(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse certificate: %w", err)
	}

	if !cert.BasicConstraintsValid {
		return fmt.Errorf("certificate does not have valid Basic Constraints extension")
	}

	if !cert.IsCA {
		return fmt.Errorf("certificate is not a CA certificate")
	}

	// Check Key Usage for certificate signing
	if cert.KeyUsage&x509.KeyUsageCertSign == 0 {
		return fmt.Errorf("certificate does not have Certificate Sign key usage")
	}

	return nil
}

// updateWatchLabel adds a watch label to any Kubernetes object that supports labels.
func (r *Reconciler) updateWatchLabel(obj client.Object, istiocsr *v1alpha1.IstioCSR) error {
	labels := obj.GetLabels()
	if labels == nil {
		labels = make(map[string]string)
	}
	labels[IstiocsrResourceWatchLabelName] = fmt.Sprintf(istiocsrResourceWatchLabelValueFmt, istiocsr.GetNamespace(), istiocsr.GetName())
	obj.SetLabels(labels)

	if err := r.UpdateWithRetry(r.ctx, obj); err != nil {
		return fmt.Errorf("failed to update %s resource with watch label: %w", obj.GetName(), err)
	}
	return nil
}

package trustmanager

import (
	"fmt"
	"maps"
	"os"
	"reflect"
	"slices"

	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/utils/ptr"
	"sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/openshift/cert-manager-operator/api/operator/v1alpha1"
	"github.com/openshift/cert-manager-operator/pkg/controller/common"
	"github.com/openshift/cert-manager-operator/pkg/operator/assets"
)

func (r *Reconciler) createOrApplyDeployment(trustManager *v1alpha1.TrustManager, resourceLabels, resourceAnnotations map[string]string, caBundleHash string) error {
	desired, err := r.getDeploymentObject(trustManager, resourceLabels, resourceAnnotations, caBundleHash)
	if err != nil {
		return err
	}

	deploymentName := fmt.Sprintf("%s/%s", desired.GetNamespace(), desired.GetName())
	r.log.V(4).Info("reconciling deployment resource", "name", deploymentName)

	existing := &appsv1.Deployment{}
	exists, err := r.Exists(r.ctx, client.ObjectKeyFromObject(desired), existing)
	if err != nil {
		return common.FromClientError(err, "failed to check if deployment %q exists", deploymentName)
	}
	if exists && !deploymentModified(desired, existing) {
		r.log.V(4).Info("deployment resource exists and is in desired state", "name", deploymentName)
		return nil
	}

	r.log.V(2).Info("deployment resource has been modified, updating to desired state", "name", deploymentName)
	if err := r.Patch(r.ctx, desired, client.Apply, client.FieldOwner(fieldOwner), client.ForceOwnership); err != nil {
		return common.FromClientError(err, "failed to apply deployment %q", deploymentName)
	}

	r.eventRecorder.Eventf(trustManager, corev1.EventTypeNormal, "Reconciled", "deployment resource %s applied", deploymentName)
	return nil
}

func (r *Reconciler) getDeploymentObject(trustManager *v1alpha1.TrustManager, resourceLabels, resourceAnnotations map[string]string, caBundleHash string) (*appsv1.Deployment, error) {
	deployment := common.DecodeObjBytes[*appsv1.Deployment](codecs, appsv1.SchemeGroupVersion, assets.MustAsset(deploymentAssetName))

	if err := validateDeploymentManifest(deployment); err != nil {
		return nil, common.NewIrrecoverableError(err, "invalid trust-manager deployment manifest")
	}

	common.UpdateName(deployment, trustManagerDeploymentName)
	common.UpdateNamespace(deployment, operandNamespace)
	common.UpdateResourceLabels(deployment, resourceLabels)
	updateResourceAnnotations(deployment, resourceAnnotations)
	updatePodTemplateLabels(deployment, resourceLabels)
	updateDeploymentArgs(deployment, trustManager)

	updateServiceAccountName(deployment)
	updateTLSSecretVolume(deployment)
	updateDefaultCAPackageVolume(
		deployment,
		trustManager.Spec.TrustManagerConfig.DefaultCAPackage,
		caBundleHash,
	)

	if err := updateImage(deployment); err != nil {
		return nil, common.NewIrrecoverableError(err, "failed to update trust-manager image")
	}

	if err := updateResourceRequirements(deployment, trustManager); err != nil {
		return nil, err
	}
	if err := updateAffinityRules(deployment, trustManager); err != nil {
		return nil, err
	}
	if err := updatePodTolerations(deployment, trustManager); err != nil {
		return nil, err
	}
	if err := updateNodeSelector(deployment, trustManager); err != nil {
		return nil, err
	}

	return deployment, nil
}

// validateDeploymentManifest checks that the bindata deployment contains the
// expected container and TLS volume. Without these, the update helpers silently
// no-op and the operator would apply a deployment with stale defaults.
func validateDeploymentManifest(deployment *appsv1.Deployment) error {
	hasContainer := false
	for _, c := range deployment.Spec.Template.Spec.Containers {
		if c.Name == trustManagerContainerName {
			hasContainer = true
			break
		}
	}
	if !hasContainer {
		return fmt.Errorf("deployment manifest missing required container %q", trustManagerContainerName)
	}

	hasVolume := false
	for _, v := range deployment.Spec.Template.Spec.Volumes {
		if v.Name == tlsVolumeName && v.Secret != nil {
			hasVolume = true
			break
		}
	}
	if !hasVolume {
		return fmt.Errorf("deployment manifest missing required secret volume %q", tlsVolumeName)
	}

	return nil
}

func updatePodTemplateLabels(deployment *appsv1.Deployment, resourceLabels map[string]string) {
	deployment.Spec.Template.Labels = resourceLabels
}

func updateDeploymentArgs(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) {
	config := trustManager.Spec.TrustManagerConfig
	trustNamespace := getTrustNamespace(trustManager)

	args := []string{
		fmt.Sprintf("--log-format=%s", config.LogFormat),
		fmt.Sprintf("--log-level=%d", config.LogLevel),
		"--metrics-port=9402",
		"--readiness-probe-port=6060",
		"--readiness-probe-path=/readyz",
		"--leader-elect=true",
		"--leader-election-lease-duration=15s",
		"--leader-election-renew-deadline=10s",
		fmt.Sprintf("--trust-namespace=%s", trustNamespace),
		"--webhook-host=0.0.0.0",
		"--webhook-port=6443",
		"--webhook-certificate-dir=/tls",
	}

	if secretTargetsEnabled(config.SecretTargets) {
		args = append(args, "--secret-targets-enabled=true")
	}

	if config.FilterExpiredCertificates == v1alpha1.FilterExpiredCertificatesPolicyEnabled {
		args = append(args, "--filter-expired-certificates=true")
	}

	if defaultCAPackageEnabled(config.DefaultCAPackage) {
		args = append(args, fmt.Sprintf("--default-package-location=%s", defaultCAPackageLocation))
	}

	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Args = args
		}
	}
}

// updateDefaultCAPackageVolume adds the default CA package ConfigMap volume
// and mount to the deployment when the feature is enabled. It also sets the
// hash annotation on the pod template to trigger rolling restarts when the
// CA bundle content changes.
func updateDefaultCAPackageVolume(deployment *appsv1.Deployment, config v1alpha1.DefaultCAPackageConfig, caBundleHash string) {
	if !defaultCAPackageEnabled(config) {
		return
	}

	if deployment.Spec.Template.Annotations == nil {
		deployment.Spec.Template.Annotations = make(map[string]string)
	}
	deployment.Spec.Template.Annotations[defaultCAPackageHashAnnotation] = caBundleHash

	// Remove any existing volume with the same name to avoid duplicates.
	var volumes []corev1.Volume
	for _, vol := range deployment.Spec.Template.Spec.Volumes {
		if vol.Name != defaultCAPackageVolumeName {
			volumes = append(volumes, vol)
		}
	}
	deployment.Spec.Template.Spec.Volumes = append(volumes, corev1.Volume{
		Name: defaultCAPackageVolumeName,
		VolumeSource: corev1.VolumeSource{
			ConfigMap: &corev1.ConfigMapVolumeSource{
				LocalObjectReference: corev1.LocalObjectReference{
					Name: defaultCAPackageConfigMapName,
				},
			},
		},
	})

	// Remove any existing volume mount at the same path, then add ours.
	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			var mounts []corev1.VolumeMount
			for _, vm := range container.VolumeMounts {
				if vm.MountPath != defaultCAPackageMountPath {
					mounts = append(mounts, vm)
				}
			}
			deployment.Spec.Template.Spec.Containers[i].VolumeMounts = append(mounts, corev1.VolumeMount{
				Name:      defaultCAPackageVolumeName,
				MountPath: defaultCAPackageMountPath,
				ReadOnly:  true,
			})
			break
		}
	}
}

func updateImage(deployment *appsv1.Deployment) error {
	image := os.Getenv(trustManagerImageNameEnvVarName)
	if image == "" {
		return fmt.Errorf("%s environment variable with trust-manager image not set", trustManagerImageNameEnvVarName)
	}
	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Image = image
		}
	}
	return nil
}

func updateResourceRequirements(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
	resources := trustManager.Spec.TrustManagerConfig.Resources
	if len(resources.Limits) == 0 && len(resources.Requests) == 0 {
		return nil
	}
	if err := common.ValidateResourceRequirements(resources, trustManagerConfigFieldPath); err != nil {
		return err
	}
	for i := range deployment.Spec.Template.Spec.Containers {
		if deployment.Spec.Template.Spec.Containers[i].Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Resources = resources
		}
	}
	return nil
}

func updateAffinityRules(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
	if trustManager.Spec.TrustManagerConfig.Affinity == nil {
		return nil
	}
	if err := common.ValidateAffinityRules(trustManager.Spec.TrustManagerConfig.Affinity, trustManagerConfigFieldPath); err != nil {
		return err
	}
	deployment.Spec.Template.Spec.Affinity = trustManager.Spec.TrustManagerConfig.Affinity
	return nil
}

func updatePodTolerations(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
	if trustManager.Spec.TrustManagerConfig.Tolerations == nil {
		return nil
	}
	if err := common.ValidateTolerationsConfig(trustManager.Spec.TrustManagerConfig.Tolerations, trustManagerConfigFieldPath); err != nil {
		return err
	}
	deployment.Spec.Template.Spec.Tolerations = trustManager.Spec.TrustManagerConfig.Tolerations
	return nil
}

func updateNodeSelector(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
	if trustManager.Spec.TrustManagerConfig.NodeSelector == nil {
		return nil
	}
	if err := common.ValidateNodeSelectorConfig(trustManager.Spec.TrustManagerConfig.NodeSelector, trustManagerConfigFieldPath); err != nil {
		return err
	}
	if deployment.Spec.Template.Spec.NodeSelector == nil {
		deployment.Spec.Template.Spec.NodeSelector = make(map[string]string)
	}
	// Merge user-specified node selectors with any default selectors from the manifest.
	// User-specified selectors take precedence.
	for k, v := range trustManager.Spec.TrustManagerConfig.NodeSelector {
		deployment.Spec.Template.Spec.NodeSelector[k] = v
	}
	return nil
}

func updateServiceAccountName(deployment *appsv1.Deployment) {
	deployment.Spec.Template.Spec.ServiceAccountName = trustManagerServiceAccountName
}

const tlsVolumeName = "tls"

func updateTLSSecretVolume(deployment *appsv1.Deployment) {
	for i, vol := range deployment.Spec.Template.Spec.Volumes {
		if vol.Name == tlsVolumeName && vol.Secret != nil {
			deployment.Spec.Template.Spec.Volumes[i].Secret.SecretName = trustManagerTLSSecretName
			return
		}
	}
}

// deploymentModified compares only the fields we manage via SSA.
// For the readiness probe, only the fields explicitly set in our bindata are
// compared to avoid false positives from API-server-defaulted probe scalars
// (TimeoutSeconds, SuccessThreshold, FailureThreshold).
func deploymentModified(desired, existing *appsv1.Deployment) bool {
	if managedMetadataModified(desired, existing) {
		return true
	}

	if !ptr.Equal(desired.Spec.Replicas, existing.Spec.Replicas) ||
		!reflect.DeepEqual(desired.Spec.Selector, existing.Spec.Selector) {
		return true
	}

	if !maps.Equal(desired.Spec.Template.Labels, existing.Spec.Template.Labels) ||
		!maps.Equal(desired.Spec.Template.Annotations, existing.Spec.Template.Annotations) {
		return true
	}

	desiredPodSpec := desired.Spec.Template.Spec
	existingPodSpec := existing.Spec.Template.Spec

	if desiredPodSpec.ServiceAccountName != existingPodSpec.ServiceAccountName ||
		!maps.Equal(desiredPodSpec.NodeSelector, existingPodSpec.NodeSelector) ||
		!reflect.DeepEqual(desiredPodSpec.Volumes, existingPodSpec.Volumes) ||
		!reflect.DeepEqual(desiredPodSpec.Affinity, existingPodSpec.Affinity) ||
		!reflect.DeepEqual(desiredPodSpec.Tolerations, existingPodSpec.Tolerations) {
		return true
	}

	if len(desiredPodSpec.Containers) != len(existingPodSpec.Containers) {
		return true
	}

	for i := range desiredPodSpec.Containers {
		if containerModified(&desiredPodSpec.Containers[i], &existingPodSpec.Containers[i]) {
			return true
		}
	}

	return false
}

func containerModified(desired, existing *corev1.Container) bool {
	if desired.Name != existing.Name ||
		desired.Image != existing.Image ||
		desired.ImagePullPolicy != existing.ImagePullPolicy {
		return true
	}

	if !slices.Equal(desired.Args, existing.Args) ||
		!reflect.DeepEqual(desired.Resources, existing.Resources) ||
		!reflect.DeepEqual(desired.SecurityContext, existing.SecurityContext) ||
		!reflect.DeepEqual(desired.VolumeMounts, existing.VolumeMounts) {
		return true
	}

	if !containerPortsMatch(desired.Ports, existing.Ports) {
		return true
	}

	if readinessProbeModified(desired.ReadinessProbe, existing.ReadinessProbe) {
		return true
	}

	return false
}

func containerPortsMatch(desired, existing []corev1.ContainerPort) bool {
	if len(desired) != len(existing) {
		return false
	}
	for _, dp := range desired {
		matched := false
		for _, ep := range existing {
			if dp.ContainerPort == ep.ContainerPort && dp.Name == ep.Name {
				matched = true
				break
			}
		}
		if !matched {
			return false
		}
	}
	return true
}

// readinessProbeModified compares only the probe fields we explicitly set in
// bindata (HTTPGet, InitialDelaySeconds, PeriodSeconds), avoiding
// API-server-defaulted int32 fields like TimeoutSeconds and FailureThreshold.
func readinessProbeModified(desired, existing *corev1.Probe) bool {
	if desired == nil && existing == nil {
		return false
	}
	if desired == nil || existing == nil {
		return true
	}
	if desired.InitialDelaySeconds != existing.InitialDelaySeconds ||
		desired.PeriodSeconds != existing.PeriodSeconds {
		return true
	}
	if desired.HTTPGet != nil && existing.HTTPGet != nil {
		if desired.HTTPGet.Path != existing.HTTPGet.Path ||
			desired.HTTPGet.Port != existing.HTTPGet.Port {
			return true
		}
	} else if desired.HTTPGet != existing.HTTPGet {
		return true
	}
	return false
}

