				d := validDeployment()
				d.Spec.Template.Spec.Volumes = []corev1.Volume{
					{Name: "unrelated-volume"},
				}
				return d
			}(),
			requiredVolumes: []string{"tls-cert"},
			wantErr:         `deployment manifest missing required volume "tls-cert"`,
		},
		{
			name: "missing one of multiple required volumes",
			deployment: func() *appsv1.Deployment {
				d := validDeployment()
				d.Spec.Template.Spec.Volumes = []corev1.Volume{
					{Name: "vol-a"},
